/**
 * 用于测试 dialog 在各种情形下 inset 计算是否正常
 */
import * as React from 'react';
import type { ModalProps } from '..';
import { Dialog } from '..';
import { useStyleSheetOnce } from '../../hooks';
import type { DialogLayoutModeProps } from '../dialog';
import { DialogLayoutMode } from '../dialog';

export interface DialogTestDemoBasicProps extends ModalProps {
  layoutMode?: DialogLayoutModeProps['mode'];
  bodyHeight?: number | string;
  injectedStyle?: string;
}

export default ({ bodyHeight = 0, injectedStyle = '', layoutMode = '2.18.0', ...props }: DialogTestDemoBasicProps) => {
  useStyleSheetOnce(injectedStyle);
  return (
    <DialogLayoutMode mode={layoutMode}>
      <Dialog {...props}>
        <div
          style={{
            height: bodyHeight,
            background: 'var(--primary-fill-default)',
          }}
        />
      </Dialog>
    </DialogLayoutMode>
  );
};
